# -*- coding: utf-8 -*-
"""brand_audit.py -- Score brand consistency across CEX artifacts.

Scans all artifacts referencing brand variables and scores consistency
across 6 dimensions. Uses brand_config.yaml as reference.

Usage:
    python _tools/brand_audit.py [--config path] [--json] [--verbose]
"""
import sys
import re
from pathlib import Path
from collections import defaultdict

try:
    import yaml
except ImportError:
    import subprocess
    subprocess.check_call([sys.executable, "-m", "pip", "install", "pyyaml", "-q"])
    import yaml

ROOT = Path(__file__).resolve().parent.parent
BRAND_CONFIG = ROOT / ".cex" / "brand" / "brand_config.yaml"

WEIGHTS = {
    "archetype_alignment": 0.25,
    "voice_consistency": 0.20,
    "visual_coherence": 0.20,
    "positioning_clarity": 0.15,
    "narrative_integrity": 0.10,
    "config_completeness": 0.10,
}


def load_brand_config(path: Path = BRAND_CONFIG) -> dict:
    if not path.exists():
        return {}
    with open(path, "r", encoding="utf-8") as f:
        return yaml.safe_load(f) or {}


def is_placeholder(value) -> bool:
    if value is None:
        return True
    s = str(value)
    return s.startswith("{{") and s.endswith("}}")


def scan_brand_references(root: Path) -> dict:
    """Scan .md files for {{BRAND_*}} references and resolved brand values."""
    refs = defaultdict(list)
    brand_pattern = re.compile(r"\{\{(BRAND_[A-Z_]+)\}\}")
    skip = {".git", "node_modules", ".cex", "_tools", "compiled"}

    for md in root.rglob("*.md"):
        if any(s in md.parts for s in skip):
            continue
        try:
            content = md.read_text(encoding="utf-8")
        except (UnicodeDecodeError, PermissionError):
            continue
        matches = brand_pattern.findall(content)
        if matches:
            refs[str(md.relative_to(root))] = list(set(matches))
    return dict(refs)


def score_config_completeness(config: dict) -> tuple:
    """Score brand_config completeness (0-1)."""
    required = [
        ("identity", "BRAND_NAME"), ("identity", "BRAND_TAGLINE"),
        ("identity", "BRAND_MISSION"), ("identity", "BRAND_VALUES"),
        ("archetype", "BRAND_ARCHETYPE"),
        ("voice", "BRAND_VOICE_TONE"), ("voice", "BRAND_VOICE_FORMALITY"),
        ("audience", "BRAND_ICP"), ("audience", "BRAND_TRANSFORMATION"),
        ("visual", "BRAND_COLORS"),
        ("positioning", "BRAND_CATEGORY"), ("positioning", "BRAND_UVP"),
        ("monetization", "BRAND_PRICING_MODEL"),
    ]
    filled = 0
    issues = []
    for section, field in required:
        if section in config and field in config[section]:
            val = config[section][field]
            if not is_placeholder(val):
                filled += 1
            else:
                issues.append(f"{field} is placeholder")
        else:
            issues.append(f"{field} missing")

    return filled / len(required), issues


def score_archetype_alignment(config: dict) -> tuple:
    """Score archetype consistency."""
    arch = config.get("archetype", {})
    issues = []
    score = 0.0

    if "BRAND_ARCHETYPE" in arch and not is_placeholder(arch["BRAND_ARCHETYPE"]):
        valid = {"creator", "hero", "sage", "explorer", "rebel", "magician",
                 "lover", "caregiver", "jester", "ruler", "innocent", "everyman"}
        if arch["BRAND_ARCHETYPE"].lower() in valid:
            score += 0.5
        else:
            issues.append(f"Invalid archetype: {arch['BRAND_ARCHETYPE']}")

        if "BRAND_PERSONALITY" in arch and not is_placeholder(arch.get("BRAND_PERSONALITY")):
            traits = arch["BRAND_PERSONALITY"]
            if isinstance(traits, list) and len(traits) >= 3:
                score += 0.3
            else:
                issues.append("Need 3+ personality traits")

        if "BRAND_ARCHETYPE_SHADOW" in arch and not is_placeholder(arch.get("BRAND_ARCHETYPE_SHADOW")):
            score += 0.2
        else:
            issues.append("No shadow archetype defined")

# brand_config_schema.yaml
# Validates .cex/brand/brand_config.yaml
# 7 sections, 13 required fields, 38 optional fields
# Derived variables (BRAND_SLUG, BRAND_UPPER, BRAND_NAME_SHORT) computed by brand_inject.py
# Aliases (BRAND_TONE->BRAND_VOICE_TONE, BRAND_VOICE->BRAND_VOICE_TONE, BRAND_NICHE->BRAND_CATEGORY) handled by brand_inject.py

type: object
required: [identity, archetype, voice, audience, visual, positioning, monetization]

properties:
  identity:
    type: object
    required: [BRAND_NAME, BRAND_TAGLINE, BRAND_MISSION, BRAND_VALUES]
    properties:
      BRAND_NAME:       { type: string, minLength: 1, maxLength: 100 }
      BRAND_TAGLINE:    { type: string, minLength: 10, maxLength: 100 }
      BRAND_SLOGAN:     { type: string }
      BRAND_MISSION:    { type: string, minLength: 20, maxLength: 500 }
      BRAND_VISION:     { type: string }
      BRAND_VALUES:     { type: array, items: { type: string }, minItems: 3, maxItems: 7 }
      BRAND_STORY:      { type: string, minLength: 200, maxLength: 2000 }
      BRAND_BIO:        { type: string, maxLength: 300 }
      BRAND_ESSENCE:    { type: string, maxLength: 50 }
      BRAND_MANIFESTO:  { type: string, maxLength: 3000 }

  archetype:
    type: object
    required: [BRAND_ARCHETYPE]
    properties:
      BRAND_ARCHETYPE:
        type: string
        enum: [creator, hero, sage, explorer, rebel, magician, lover, caregiver, jester, ruler, innocent, everyman]
      BRAND_ARCHETYPE_SHADOW:  { type: string }
      BRAND_PERSONALITY:       { type: array, items: { type: string }, minItems: 3, maxItems: 7 }

  voice:
    type: object
    required: [BRAND_VOICE_TONE, BRAND_VOICE_FORMALITY]
    properties:
      BRAND_VOICE_TONE:        { type: string }
      BRAND_VOICE_FORMALITY:   { type: integer, minimum: 1, maximum: 5 }
      BRAND_VOICE_ENTHUSIASM:  { type: integer, minimum: 1, maximum: 5 }
      BRAND_VOICE_HUMOR:       { type: integer, minimum: 1, maximum: 5 }
      BRAND_VOICE_WARMTH:      { type: integer, minimum: 1, maximum: 5 }
      BRAND_VOICE_AUTHORITY:   { type: integer, minimum: 1, maximum: 5 }
      BRAND_VOICE_DO:          { type: array, items: { type: string }, minItems: 3 }
      BRAND_VOICE_DONT:        { type: array, items: { type: string }, minItems: 3 }
      BRAND_LANGUAGE:          { type: string, pattern: "^[a-z]{2}-[A-Z]{2}$" }
      BRAND_PERSON:            { type: string, enum: ["1st", "2nd", "3rd"] }
      BRAND_ENERGY:            { type: string, enum: [calm, moderate, energetic, bold] }

  audience:
    type: object
    required: [BRAND_ICP, BRAND_TRANSFORMATION]
    properties:
      BRAND_ICP:              { type: string, minLength: 20 }
      BRAND_ICP_AGE:          { type: string }
      BRAND_ICP_LOCATION:     { type: string }
      BRAND_ICP_INCOME:       { type: string }
      BRAND_ICP_VALUES:       { type: array, items: { type: string } }
      BRAND_ICP_FEARS:        { type: array, items: { type: string } }
      BRAND_ICP_ASPIRATIONS:  { type: array, items: { type: string } }
      BRAND_TRANSFORMATION:   { type: string, pattern: "From .+ to .+ through .+" }
      BRAND_COUNTRY:          { type: string, pattern: "^[A-Z]{2}$" }

  visual:
    type: object
    required: [BRAND_COLORS]
    properties:
      BRAND_COLORS:
        type: object
        required: [primary, secondary, accent]
        properties:
          primary:    { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
          secondary:  { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
          accent:     { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
          background: { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
          foreground: { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
          surface:    { type: string, pattern: "^#[0-9a-fA-F]{6}$" }
      BRAND_FONTS:
        type: object
        properties:
          heading: { type: string }
          body:    { type: string }
          mono:    { type: string }
      BRAND_LOGO_URL:    { type: string, format: uri }
